84	  onDriftClick,
85	}: StatusBarProps): JSX.Element {
86	  return (
87	    <div
88	      data-testid="status-bar"
89	      role="contentinfo"
90	      style={statusStyle}
91	      className="relative flex w-full items-center gap-3 border-t border-border bg-surface px-4 text-xs"
92	    >
93	      <LevelCluster level={level} levels={levels} onLevelChange={onLevelChange} />
94	      <Divider />
95	      <ToolCluster toolLabel={toolLabel ?? null} />
96	      <Divider />
