98	      <Divider />
99	      <GridCluster gridOn={gridOn} onGridToggle={onGridToggle} />
100	      <Divider />
101	      <CoordCluster cursorMm={cursorMm ?? null} />
102	      <div className="ml-auto flex items-center gap-3">
103	        {conflictQueue ? (
